(window.webpackJsonp=window.webpackJsonp||[]).push([[66],{440:function(n,e,l){"use strict";l.r(e);var t=l(11),r=Object(t.a)({},(function(){var n=this,e=n._self._c;return e("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[e("p",[n._v("AI 大模型简介")]),n._v(" "),e("ol",[e("li",[n._v("什么是 AI 大模型\nAI 大模型（Large Language Model，简称 LLM，广义包含多模态大模型）是基于深度学习、拥有海量参数、海量训练数据的人工智能基础模型，核心依托 Transformer 架构构建。\n“大” 主要体现在两点：\n参数规模大：从数十亿到万亿级神经网络参数；\n训练数据量大：使用全网文本、图片、音视频等海量公开数据预训练。\n区别于传统小模型（只能完成单一任务：图像识别、翻译、分类），大模型属于基础通用模型，一次预训练后可适配对话、写作、代码、画图、推理等上百种任务。")]),n._v(" "),e("li",[n._v("核心技术底座：Transformer\n2017 年 Google 发布《Attention Is All You Need》提出 Transformer 架构，是所有现代大模型的根基，核心机制：\n自注意力机制（Self-Attention）：模型能自主识别文本、图像中不同内容的关联关系，理解上下文逻辑；\n编码器 + 解码器：负责理解输入内容、生成连贯输出；\n并行计算：相比传统 RNN 循环网络，训练速度大幅提升，支撑超大模型训练。")]),n._v(" "),e("li",[n._v("两大主流类型\n3.1 大语言模型 LLM（文本类）\n仅以文字数据训练，擅长处理语言逻辑：\n能力：对话问答、文案写作、代码生成、逻辑推理、总结翻译、数学计算、方案策划；\n代表：GPT 系列、文心一言、通义千问、DeepSeek、Llama、Qwen 通义千问开源版等。\n3.2 多模态大模型 MLLM\n同时训练文本、图片、音频、视频数据，可跨媒介理解与生成：\n能力：看图提问、文生图、图文总结、语音对话、视频理解、图文混合创作；\n代表：GPT-4V、文心一格、通义万相、Qwen-VL、Midjourney 配套大模型等。")]),n._v(" "),e("li",[n._v("完整工作流程\n4.1 预训练阶段（基础能力塑造）\n收集海量合规文本、图像、音视频数据；\n数据清洗去重、过滤不良内容；\n输入 Transformer 网络进行无监督学习；\n模型学习通用语言、常识、世界知识，形成基础认知。\n4.2 微调阶段（定向优化）\n预训练后的基础模型通用性强但不贴合人类习惯，通过少量标注数据微调：\nSFT 监督微调：人工标注问答对话，让模型学会人类表达习惯；\nRLHF 人类反馈强化学习：根据人类打分优化回答逻辑、真实性、安全性，减少幻觉。\n4.3 推理阶段（用户实际使用）\n用户输入提示词（Prompt），模型实时计算生成输出内容，可通过 API、网页客户端、本地部署三种方式调用。")]),n._v(" "),e("li",[n._v("核心能力\n上下文理解：支持长文本记忆，可基于几千至百万字上下文连续对话；\n逻辑推理：数学运算、逻辑证明、复杂问题拆解、方案推演；\n生成创作：文章、代码、诗歌、剧本、图像、音频、PPT 文案自动生成；\n工具调用：联网搜索、代码运行、读取文件、操作第三方工具，弥补知识时效性短板；\n泛化能力：未学习过的全新任务，仅靠简单指令即可完成，无需单独训练模型。")]),n._v(" "),e("li",[n._v("优势与局限性\n6.1 优势\n一站式通用能力，一套模型覆盖多场景，降低 AI 开发成本；\n低门槛使用，普通人通过自然语言即可完成复杂工作；\n开源生态成熟，企业可本地私有化部署，保障数据安全。\n6.2 局限性\n模型幻觉：会编造不存在事实、数据、文献，专业内容需人工核验；\n知识时效性限制：预训练数据存在时间截止点，无法自动获取实时新闻；\n上下文长度上限：超长内容易丢失远端信息；\n偏见问题：训练数据自带人类社会偏见，可能输出片面观点；\n算力成本高：训练、运行超大模型需要高性能 GPU，硬件开销大。")]),n._v(" "),e("li",[n._v("应用领域\n办公效率：文档总结、表格分析、PPT 生成、邮件撰写、数据整理；\n软件开发：代码编写、bug 排查、接口文档生成、脚本开发；\n教育行业：知识点讲解、题库生成、作文批改、个性化学习辅导；\n文创设计：文案、插画、短视频脚本、海报设计、音频配音；\n工业企业：方案设计、设备故障分析、行业报告、流程优化；\n生活服务：智能客服、旅行规划、心理咨询辅助、翻译工具。")]),n._v(" "),e("li",[n._v("发展趋势\n轻量化：小参数开源大模型兴起，可在个人电脑、手机本地运行；\n多模态统一：文本、图像、音频、视频、3D 模型融合一体的大一统模型；\nAgent 智能体：大模型自主规划、调用工具、完成复杂长流程任务；\n行业专用模型：针对医疗、法律、工业垂直领域微调专业大模型；\n安全对齐升级：降低幻觉、增强事实准确性、完善内容安全管控；\n国产化开源生态：国内开源大模型持续迭代，降低行业使用门槛。")]),n._v(" "),e("li",[n._v("总结\nAI 大模型是人工智能发展的里程碑式技术，打破了传统 AI “一任务一模型” 的局限，凭借强大的通用理解与生成能力重构办公、生产、创作各行业。\n现阶段大模型仍存在幻觉、时效性等短板，使用中需结合人工校验；未来随着轻量化、智能体、多模态技术迭代，将进一步深度融入日常生产生活。")])])])}),[],!1,null,null,null);e.default=r.exports}}]);